export type Options<TData extends TDataShape = TDataShape, ThrowOnError extends boolean = boolean> = ClientOptions<TData, ThrowOnError> & {
    /**
     * You can provide a client instance returned by `createClient()` instead of
     * individual options. This might be also useful if you want to implement a
     * custom client.
     */
    client?: Client;
    /**
     * You can pass arbitrary values through the `meta` object. This can be
     * used to access values that aren't defined as part of the SDK function.
     */
    meta?: Record<string, unknown>;
};

/**
 * Get platform information
 */
export const getPlatformInfo = <ThrowOnError extends boolean = false>(options?: Options<GetPlatformInfoData, ThrowOnError>) => {
    return (options?.client ?? client).get<GetPlatformInfoResponses, GetPlatformInfoErrors, ThrowOnError>({
        security: [
            {
                scheme: 'bearer',
                type: 'http'
            }
        ],
        url: '/.well-known/temps.json',
        ...options
    });
};

/**
 * Chunk upload options (stub for sentry-cli compatibility).
 * sentry-cli checks this endpoint to determine if chunk-based upload is supported.
 * We return a response indicating that chunk upload is NOT supported, which forces
 * sentry-cli to fall back to the standard file-by-file upload.
 */
export const chunkUploadOptions = <ThrowOnError extends boolean = false>(options: Options<ChunkUploadOptionsData, ThrowOnError>) => {
    return (options.client ?? client).get<ChunkUploadOptionsResponses, unknown, ThrowOnError>({
        url: '/0/organizations/{org_slug}/chunk-upload/',
        ...options
    });
};

/**
 * Create a release (stub for sentry-cli compatibility).
 * sentry-cli calls this before uploading files. Since Temps implicitly creates
 * releases when source maps are uploaded, this is a no-op that returns the
 * expected response format.
 */
export const createRelease = <ThrowOnError extends boolean = false>(options: Options<CreateReleaseData, ThrowOnError>) => {
    return (options.client ?? client).post<CreateReleaseResponses, CreateReleaseErrors, ThrowOnError>({
        url: '/0/organizations/{org_slug}/releases/',
        ...options,
        headers: {
            'Content-Type': 'application/json',
            ...options.headers
        }
    });
};

/**
 * List files for a release.
 * Returns all source maps stored for a specific release in sentry-cli compatible format.
 */
export const listReleaseFiles = <ThrowOnError extends boolean = false>(options: Options<ListReleaseFilesData, ThrowOnError>) => {
    return (options.client ?? client).get<ListReleaseFilesResponses, ListReleaseFilesErrors, ThrowOnError>({
        url: '/0/projects/{org_slug}/{project_slug}/releases/{version}/files/',
        ...options
    });
};

